    22→	"math"
    23→	"sync"
    24→	"testing"
    25→	"time"
    26→
    27→	apps "k8s.io/api/apps/v1"
    28→	v1 "k8s.io/api/core/v1"
    29→	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    30→	"k8s.io/apimachinery/pkg/util/wait"
    31→	"k8s.io/client-go/informers"
    32→	clientset "k8s.io/client-go/kubernetes"
    33→	restclient "k8s.io/client-go/rest"
    34→	kubeapiservertesting "k8s.io/kubernetes/cmd/kube-apiserver/app/testing"
    35→	podutil "k8s.io/kubernetes/pkg/api/v1/pod"
    36→	"k8s.io/kubernetes/pkg/controller/deployment"
    37→	deploymentutil "k8s.io/kubernetes/pkg/controller/deployment/util"
    38→	"k8s.io/kubernetes/pkg/controller/replicaset"
    39→	"k8s.io/kubernetes/test/integration/framework"
    40→	testutil "k8s.io/kubernetes/test/utils"
    41→	"k8s.io/utils/ptr"
    42→)
    43→
    44→const (
    45→	pollInterval = 100 * time.Millisecond
    46→	pollTimeout  = 60 * time.Second
    47→
    48→	fakeContainerName = "fake-name"
    49→	fakeImage         = "fakeimage"
    50→)
    51→
    52→var pauseFn = func(update *apps.Deployment) {
    53→	update.Spec.Paused = true
    54→}
    55→
    56→var resumeFn = func(update *apps.Deployment) {
    57→	update.Spec.Paused = false
    58→}
    59→
    60→type deploymentTester struct {
    61→	t          *testing.T
    62→	c          clientset.Interface
    63→	deployment *apps.Deployment
    64→}
    65→
    66→func testLabels() map[string]string {
    67→	return map[string]string{"name": "test"}
    68→}
    69→
    70→// newDeployment returns a RollingUpdate Deployment with a fake container image
    71→func newDeployment(name, ns string, replicas int32) *apps.Deployment {
    72→	return &apps.Deployment{
    73→		TypeMeta: metav1.TypeMeta{
    74→			Kind:       "Deployment",
    75→			APIVersion: "apps/v1",
    76→		},
    77→		ObjectMeta: metav1.ObjectMeta{
    78→			Namespace: ns,
    79→			Name:      name,
    80→		},
    81→		Spec: apps.DeploymentSpec{
    82→			Replicas: &replicas,
    83→			Selector: &metav1.LabelSelector{MatchLabels: testLabels()},
    84→			Strategy: apps.DeploymentStrategy{
    85→				Type:          apps.RollingUpdateDeploymentStrategyType,
    86→				RollingUpdate: new(apps.RollingUpdateDeployment),
    87→			},
    88→			Template: v1.PodTemplateSpec{
    89→				ObjectMeta: metav1.ObjectMeta{
    90→					Labels: testLabels(),
    91→				},
    92→				Spec: v1.PodSpec{
    93→					Containers: []v1.Container{
    94→						{
    95→							Name:  fakeContainerName,
    96→							Image: fakeImage,
    97→						},
    98→					},
    99→				},
   100→			},
   101→		},
   102→	}
   103→}
   104→
   105→// dcSetup sets up necessities for Deployment integration test, including control plane, apiserver, informers, and clientset
   106→func dcSetup(ctx context.Context, t *testing.T) (kubeapiservertesting.TearDownFunc, *replicaset.ReplicaSetController, *deployment.DeploymentController, informers.SharedInformerFactory, clientset.Interface) {
   107→	// Disable ServiceAccount admission plugin as we don't have serviceaccount controller running.
   108→	server := kubeapiservertesting.StartTestServerOrDie(t, nil, framework.DefaultTestServerFlags(), framework.SharedEtcd())
   109→
   110→	config := restclient.CopyConfig(server.ClientConfig)
   111→	clientSet, err := clientset.NewForConfig(config)
   112→	if err != nil {
   113→		t.Fatalf("error in create clientset: %v", err)
   114→	}
   115→	resyncPeriod := 12 * time.Hour
   116→	informers := informers.NewSharedInformerFactory(clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "deployment-informers")), resyncPeriod)
   117→
   118→	dc, err := deployment.NewDeploymentController(
   119→		ctx,
   120→		informers.Apps().V1().Deployments(),
   121→		informers.Apps().V1().ReplicaSets(),
   122→		informers.Core().V1().Pods(),
   123→		clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "deployment-controller")),
   124→	)
   125→	if err != nil {
   126→		t.Fatalf("error creating Deployment controller: %v", err)
   127→	}
   128→	rm := replicaset.NewReplicaSetController(
   129→		ctx,
   130→		informers.Apps().V1().ReplicaSets(),
   131→		informers.Core().V1().Pods(),
   132→		clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "replicaset-controller")),
   133→		replicaset.BurstReplicas,
   134→	)
   135→	return server.TearDownFn, rm, dc, informers, clientSet
   136→}
   137→
   138→// dcSimpleSetup sets up necessities for Deployment integration test, including control plane, apiserver,
   139→// and clientset, but not controllers and informers
   140→func dcSimpleSetup(t *testing.T) (kubeapiservertesting.TearDownFunc, clientset.Interface) {
   141→	// Disable ServiceAccount admission plugin as we don't have serviceaccount controller running.
   142→	server := kubeapiservertesting.StartTestServerOrDie(t, nil, framework.DefaultTestServerFlags(), framework.SharedEtcd())
   143→
   144→	config := restclient.CopyConfig(server.ClientConfig)
   145→	clientSet, err := clientset.NewForConfig(config)
   146→	if err != nil {
   147→		t.Fatalf("error in create clientset: %v", err)
   148→	}
   149→	return server.TearDownFn, clientSet
   150→}
   151→
   152→// runControllersAndInformers runs RS and deployment controllers and informers
   153→func runControllersAndInformers(t *testing.T, rm *replicaset.ReplicaSetController, dc *deployment.DeploymentController, informers informers.SharedInformerFactory) func() {
   154→	ctx, cancelFn := context.WithCancel(context.Background())
   155→	informers.Start(ctx.Done())
   156→	go rm.Run(ctx, 5)
   157→	go dc.Run(ctx, 5)
   158→	return cancelFn
   159→}
   160→
   161→// addPodConditionReady sets given pod status to ready at given time
   162→func addPodConditionReady(pod *v1.Pod, time metav1.Time) {
   163→	pod.Status = v1.PodStatus{
   164→		Phase: v1.PodRunning,
   165→		Conditions: []v1.PodCondition{
   166→			{
   167→				Type:               v1.PodReady,
   168→				Status:             v1.ConditionTrue,
   169→				LastTransitionTime: time,
   170→			},
   171→		},
   172→	}
   173→}
   174→
   175→func (d *deploymentTester) waitForDeploymentRevisionAndImage(revision, image string) error {
   176→	if err := testutil.WaitForDeploymentRevisionAndImage(d.c, d.deployment.Namespace, d.deployment.Name, revision, image, d.t.Logf, pollInterval, pollTimeout); err != nil {
   177→		return fmt.Errorf("failed to wait for Deployment revision %s: %v", d.deployment.Name, err)
   178→	}
   179→	return nil
   180→}
   181→
   182→func markPodReady(c clientset.Interface, ns string, pod *v1.Pod) error {
   183→	addPodConditionReady(pod, metav1.Now())
   184→	_, err := c.CoreV1().Pods(ns).UpdateStatus(context.TODO(), pod, metav1.UpdateOptions{})
   185→	return err
   186→}
   187→
   188→// markUpdatedPodsReady manually marks updated Deployment pods status to ready,
   189→// until the deployment is complete
   190→func (d *deploymentTester) markUpdatedPodsReady(wg *sync.WaitGroup) {
   191→	defer wg.Done()
   192→
   193→	ns := d.deployment.Namespace
   194→	err := wait.PollImmediate(pollInterval, pollTimeout, func() (bool, error) {
   195→		// We're done when the deployment is complete
   196→		if completed, err := d.deploymentComplete(); err != nil {
   197→			return false, err
   198→		} else if completed {
   199→			return true, nil
   200→		}
   201→		// Otherwise, mark remaining pods as ready
   202→		pods, err := d.listUpdatedPods()
   203→		if err != nil {
   204→			d.t.Log(err)
   205→			return false, nil
   206→		}
   207→		d.t.Logf("%d/%d of deployment pods are created", len(pods), *d.deployment.Spec.Replicas)
   208→		for i := range pods {
   209→			pod := pods[i]
   210→			if podutil.IsPodReady(&pod) {
   211→				continue
   212→			}
   213→			if err = markPodReady(d.c, ns, &pod); err != nil {
   214→				d.t.Logf("failed to update Deployment pod %s, will retry later: %v", pod.Name, err)
   215→			}
   216→		}
   217→		return false, nil
   218→	})
   219→	if err != nil {
   220→		d.t.Errorf("failed to mark updated Deployment pods to ready: %v", err)
   221→	}
   222→}
   223→
   224→// removeTerminatedPods manually removes terminated Deployment pods,
   225→// until the deployment is complete
   226→func (d *deploymentTester) removeTerminatedPods(ctx context.Context, wg *sync.WaitGroup) {
   227→	defer wg.Done()
   228→
   229→	err := wait.PollUntilContextTimeout(ctx, pollInterval, pollTimeout, true, func(ctx context.Context) (bool, error) {
   230→		// We're done when the deployment is complete
   231→		if completed, err := d.deploymentComplete(); err != nil {
   232→			return false, err
   233→		} else if completed {
   234→			return true, nil
   235→		}
   236→		// Otherwise, mark remaining pods as ready
   237→		rsList, err := deploymentutil.ListReplicaSets(d.deployment, deploymentutil.RsListFromClient(d.c.AppsV1()))
   238→		if err != nil {
   239→			d.t.Log(err)
   240→			return false, nil
   241→		}
   242→		for _, rs := range rsList {
   243→			if err := d.removeRSPods(ctx, rs, math.MaxInt, true, 0); err != nil {
   244→				d.t.Log(err)
   245→				return false, nil
   246→			}
   247→		}
   248→		return false, nil
   249→	})
   250→	if err != nil {
   251→		d.t.Errorf("failed to remove terminated Deployment pods: %v", err)
   252→	}
   253→}
