   116→	informers := informers.NewSharedInformerFactory(clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "deployment-informers")), resyncPeriod)
   117→
   118→	dc, err := deployment.NewDeploymentController(
   119→		ctx,
   120→		informers.Apps().V1().Deployments(),
   121→		informers.Apps().V1().ReplicaSets(),
   122→		informers.Core().V1().Pods(),
   123→		clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "deployment-controller")),
   124→	)
   125→	if err != nil {
   126→		t.Fatalf("error creating Deployment controller: %v", err)
   127→	}
   128→	rm := replicaset.NewReplicaSetController(
   129→		ctx,
   130→		informers.Apps().V1().ReplicaSets(),
   131→		informers.Core().V1().Pods(),
   132→		clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "replicaset-controller")),
   133→		replicaset.BurstReplicas,
   134→	)
   135→	return server.TearDownFn, rm, dc, informers, clientSet
   136→}
   137→
   138→// dcSimpleSetup sets up necessities for Deployment integration test, including control plane, apiserver,
   139→// and clientset, but not controllers and informers
   140→func dcSimpleSetup(t *testing.T) (kubeapiservertesting.TearDownFunc, clientset.Interface) {
   141→	// Disable ServiceAccount admission plugin as we don't have serviceaccount controller running.
   142→	server := kubeapiservertesting.StartTestServerOrDie(t, nil, framework.DefaultTestServerFlags(), framework.SharedEtcd())
   143→
   144→	config := restclient.CopyConfig(server.ClientConfig)
   145→	clientSet, err := clientset.NewForConfig(config)
   146→	if err != nil {
   147→		t.Fatalf("error in create clientset: %v", err)
   148→	}
   149→	return server.TearDownFn, clientSet
   150→}
