   152→// runControllersAndInformers runs RS and deployment controllers and informers
   153→func runControllersAndInformers(t *testing.T, rm *replicaset.ReplicaSetController, dc *deployment.DeploymentController, informers informers.SharedInformerFactory) func() {
   154→	ctx, cancelFn := context.WithCancel(context.Background())
   155→	informers.Start(ctx.Done())
   156→	go rm.Run(ctx, 5)
   157→	go dc.Run(ctx, 5)
   158→	return cancelFn
