   161→// addPodConditionReady sets given pod status to ready at given time
   162→func addPodConditionReady(pod *v1.Pod, time metav1.Time) {
   163→	pod.Status = v1.PodStatus{
   164→		Phase: v1.PodRunning,
   165→		Conditions: []v1.PodCondition{
   166→			{
   167→				Type:               v1.PodReady,
   168→				Status:             v1.ConditionTrue,
   169→				LastTransitionTime: time,
   170→			},
   171→		},
   172→	}
   173→}
   174→
   175→func (d *deploymentTester) waitForDeploymentRevisionAndImage(revision, image string) error {
   176→	if err := testutil.WaitForDeploymentRevisionAndImage(d.c, d.deployment.Namespace, d.deployment.Name, revision, image, d.t.Logf, pollInterval, pollTimeout); err != nil {
   177→		return fmt.Errorf("failed to wait for Deployment revision %s: %v", d.deployment.Name, err)
   178→	}
   179→	return nil
   180→}
